import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it.todo("returns 5 G processing fee for an empty item list");
    it.todo("returns base premium plus fee for a single sword");
    it.todo("returns base premium plus fee for each main item type (amulet, staff, potion)");
    it.todo("returns 25 G base premium per component (rune)");
    it.todo("applies building block discount for exactly 3 alike components");
    it.todo("does not apply block discount for 4 alike components");
    it.todo("treats different component types separately for block eligibility");
    it.todo("sums base premiums for multiple items in a policy");
  });

  describe("Quote - item-specific modifiers", () => {
    it.todo("adds 50% cursed surcharge to the cursed item base premium");
    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
    it.todo("applies both cursed and high-enchantment surcharges to the same item");
    it.todo("applies item modifiers only to the affected item in a multi-item policy");
  });

  describe("Quote - policy-wide modifiers", () => {
    it.todo("applies 10% first-insurance surcharge on policy base premium");
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up discount on second and subsequent quotes");
    it.todo("stacks policy-wide modifiers (loyalty, first insurance, follow-up)");
  });

  describe("Quote - rounding", () => {
    it.todo("rounds premium up (in MHPCO's favor)");
  });

  describe("Quote - integration", () => {
    it.todo("newcomer with cursed sword computes to 165 G");
    it.todo("long-standing customer second contract with cursed high-enchantment sword computes to 160 G");
  });

  describe("Claim - standard reimbursement", () => {
    it.todo("reimburses damage minus 100 G deductible for a regular item");
    it.todo("reimburses component damage minus deductible");
    it.todo("applies deductible per damaged item in a single event");
  });

  describe("Claim - special clauses", () => {
    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
    it.todo("fully reimburses dragon-material items minus deductible");
    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
    it.todo("applies only dragon-material clause when enchantment < 8");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at twice the insurance sum");
    it.todo("tracks remaining cap across successive claims");
    it.todo("bases cap on unmodified insurance values");
  });

  describe("Claim - rounds payout down (in MHPCO's favor)", () => {
    it.todo("rounds payout down");
  });

  describe("Validation", () => {
    it.todo("rejects unknown item type in a quote");
    it.todo("rejects claim for item not in policy");
    it.todo("rejects claim with more damage entries than insured items of that type");
    it.todo("rejects negative damage amount");
  });
});

