const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);

function calculateBasePremium(items: any[]): number {
  const counts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts[item.type] = (counts[item.type] || 0) + 1;
    }
  }
  let premium = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      continue;
    }
    premium += BASE_PREMIUMS[item.type];
  }
  for (const [type, count] of Object.entries(counts)) {
    if (count === 3) {
      premium += COMPONENT_BLOCK_PREMIUM;
    } else {
      premium += count * BASE_PREMIUMS[type];
    }
  }
  return premium;
}

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    const basePremium = calculateBasePremium(step.items);
    const premium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

