const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const COMPONENT_BLOCK_PREMIUM = 60;

const MAIN_ITEM_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUMS: Record<string, number> = {
  rune: 25,
  moonstone: 25,
};

function calculateBasePremium(items: any[]): number {
  const componentCounts: Record<string, number> = {};
  let premium = 0;
  for (const item of items) {
    if (item.type in COMPONENT_PREMIUMS) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      premium += MAIN_ITEM_PREMIUMS[item.type];
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    premium += count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUMS[type];
  }
  return premium;
}

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    const basePremium = calculateBasePremium(step.items);
    const premium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

