const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const COMPONENT_BLOCK_PREMIUM = 60;

const MAIN_ITEM_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUMS: Record<string, number> = {
  rune: 25,
  moonstone: 25,
};

function calculateBasePremium(items: any[]): number {
  const componentCounts: Record<string, number> = {};
  let premium = 0;
  for (const item of items) {
    if (item.type in COMPONENT_PREMIUMS) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      premium += MAIN_ITEM_PREMIUMS[item.type];
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    premium += count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUMS[type];
  }
  return premium;
}

const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

function calculateSingleItemSurcharge(item: any): number {
  const basePremium = MAIN_ITEM_PREMIUMS[item.type] || 0;
  let surcharge = 0;
  if (item.cursed) {
    surcharge += basePremium * CURSED_SURCHARGE_RATE;
  }
  if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
    surcharge += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
  }
  return surcharge;
}

function calculateItemSurcharges(items: any[]): number {
  return items.reduce((total, item) => total + calculateSingleItemSurcharge(item), 0);
}

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    const basePremium = calculateBasePremium(step.items);
    const itemSurcharges = calculateItemSurcharges(step.items);
    const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
    const premium = basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

